function getNextGreaterElements(arr) {
    let n = arr.length;
    let stack = [];
    let nge = new Array(n).fill(-1);

    // Iterating the array from right to left
    for (let i = n - 1; i >= 0; i--) {
        // Pop till the top element is smaller than current
        while (stack.length && stack[stack.length - 1] <= arr[i]) {
            stack.pop();
        }

        if (stack.length) {
            nge[i] = stack[stack.length - 1];
        } else {
            nge[i] = -1;
        }

        // Push the current element to stack
        stack.push(arr[i]);
    }

    return nge;
}
